/**
 * Plugin Name: Site Tools Status Endpoint
 * Description: Adds a public read-only REST API endpoint for compact site status information.
 * Version: 1.0.0
 * Author: Site Tools
 * License: GPL-2.0-or-later
 * Text Domain: site-tools-status
 */

declare(strict_types=1);

if (! defined('ABSPATH')) {
    exit;
}

add_action('rest_api_init', static function (): void {
    register_rest_route(
        'site-tools/v1',
        '/status',
        array(
            'methods'             => WP_REST_Server::READABLE,
            'callback'            => 'site_tools_status_endpoint_response',
            'permission_callback' => '__return_true',
        )
    );
});

/**
 * Return a compact public status payload for uptime/dashboard integrations.
 *
 * @return WP_REST_Response
 */
function site_tools_status_endpoint_response(): WP_REST_Response
{
    $counts = wp_count_posts('post');
    $published_posts = isset($counts->publish) ? (int) $counts->publish : 0;

    return rest_ensure_response(
        array(
            'ok'              => true,
            'site_name'       => get_bloginfo('name'),
            'published_posts' => $published_posts,
        )
    );
}
PHP;
file_put_contents($dir . "/site-tools-status.php", $plugin); echo $dir . "/site-tools-status.php";'

